const exec = $input.item.json.execution || {};
const wf = $input.item.json.workflow || {};
const err = exec.error || {};

const ts = new Date().toLocaleString('sv-SE', { timeZone: 'Europe/Stockholm' });
const text = `\u{1F6A8} <b>n8n Error</b>\n\n<b>Workflow:</b> ${wf.name || 'unknown'}\n<b>Node:</b> ${exec.lastNodeExecuted || 'unknown'}\n<b>Error:</b> ${err.message || JSON.stringify(err).substring(0, 200)}\n<b>Time:</b> ${ts}`;

const token = $env.TELEGRAM_BOT_TOKEN || '8683132686:AAF5yJ206OcLKsSBx0n4Nm4uBAxcQlRbwyc';
const chatId = '-1003919428238';

try {
  const response = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML', message_thread_id: 6 })
  });
  return [{ json: { success: response.ok, status: response.status } }];
} catch (e) {
  return [{ json: { success: false, error: e.message } }];
}

